        // Explore all neighbors of this node
        for (let it of adj[node]) {
            // If the neighbor is not visited, recursively perform DFS
            if (vis[it] === 0) {
                this.dfs(it, adj, vis, st);
            }
        }

        // After visiting all neighbors, push this node into the stack
        st.push(node);
